/**
 * FleetOptimizationCard
 *
 * Displays the single highest-priority optimization recommendation
 * generated by the fleet optimizer. Shown on DashboardHome between
 * Memory Actions and the main content grid.
 */

import { useCallback, useMemo, useState } from 'react';
import {
  Sparkles,
  TrendingDown,
  CheckCircle2,
  ChevronDown,
  ChevronUp,
  Zap,
  DollarSign,
  Search,
  FlaskConical,
} from 'lucide-react';
import { useOverviewStore } from "@/stores/overviewStore";
import { useShallow } from 'zustand/react/shallow';
import { useTranslation } from '@/i18n/useTranslation';
import { useAgentStore } from '@/stores/agentStore';
import { useSystemStore } from '@/stores/systemStore';
import { useForwardToAthena } from '@/features/plugins/companion/useForwardToAthena';
import { Button } from '@/features/shared/components/buttons';
import { Tooltip } from '@/features/shared/components/display/Tooltip';

import {
  generateFleetRecommendation,
  type FleetRecommendation,
  type RecommendationType,
} from '@/features/overview/libs/fleetOptimizer';

// -- Icon/style mapping ----------------------------------------------

const TYPE_CONFIG: Record<RecommendationType, {
  icon: typeof Sparkles;
  accent: string;
  bg: string;
  border: string;
  badge: string;
}> = {
  downgrade_model: {
    icon: TrendingDown,
    accent: 'text-cyan-400',
    bg: 'bg-cyan-500/8',
    border: 'border-cyan-500/15',
    badge: 'bg-cyan-500/10 text-cyan-300 border-cyan-500/20',
  },
  reduce_retries: {
    icon: Zap,
    accent: 'text-amber-400',
    bg: 'bg-amber-500/8',
    border: 'border-amber-500/15',
    badge: 'bg-amber-500/10 text-amber-300 border-amber-500/20',
  },
  investigate_failures: {
    icon: Search,
    accent: 'text-rose-400',
    bg: 'bg-rose-500/8',
    border: 'border-rose-500/15',
    badge: 'bg-rose-500/10 text-rose-300 border-rose-500/20',
  },
  consolidate_personas: {
    icon: Sparkles,
    accent: 'text-violet-400',
    bg: 'bg-violet-500/8',
    border: 'border-violet-500/15',
    badge: 'bg-violet-500/10 text-violet-300 border-violet-500/20',
  },
  cost_anomaly: {
    icon: DollarSign,
    accent: 'text-red-400',
    bg: 'bg-red-500/8',
    border: 'border-red-500/15',
    badge: 'bg-red-500/10 text-red-300 border-red-500/20',
  },
  healthy_fleet: {
    icon: CheckCircle2,
    accent: 'text-emerald-400',
    bg: 'bg-emerald-500/8',
    border: 'border-emerald-500/15',
    badge: 'bg-emerald-500/10 text-emerald-300 border-emerald-500/20',
  },
};

const SEVERITY_LABEL: Record<string, string> = {
  critical: 'Urgent',
  warning: 'Suggested',
  info: 'Insight',
};

// -- Component -------------------------------------------------------

function RecommendationContent({ rec }: { rec: FleetRecommendation }) {
  const { t, tx } = useTranslation();
  const forwardToAthena = useForwardToAthena();
  const [expanded, setExpanded] = useState(false);
  const config = TYPE_CONFIG[rec.type];
  const Icon = config.icon;

  // healthy_fleet is a status, not a problem — no agent to tune, nothing to ask.
  const showActions = rec.type !== 'healthy_fleet';
  const personaId = rec.personaIds[0] ?? null;
  const personaName = rec.personaNames[0] ?? null;

  // Jump straight into the affected agent's Lab in model-comparison mode so the
  // user can test alternative models against the persona this rec is about.
  const openLab = useCallback(() => {
    if (!personaId) return;
    useSystemStore.getState().setSidebarSection('personas');
    useAgentStore.getState().selectPersona(personaId);
    useSystemStore.getState().setEditorTab('lab');
    useAgentStore.getState().setLabMode('matrix');
  }, [personaId]);

  // Forward the recommendation to Athena (companion) so she can investigate and,
  // if useful, drive the Lab herself. Routes through the orb (not the full
  // panel) with an ack glow + scripted spoken confirmation — see useForwardToAthena.
  const askAthena = useCallback(() => {
    const focus = personaName
      ? tx(t.overview.fleet_optimization.ask_athena_focus_persona, { persona: personaName })
      : t.overview.fleet_optimization.ask_athena_focus_general;
    const text = tx(t.overview.fleet_optimization.ask_athena_prompt, {
      title: rec.title,
      description: rec.description,
      action: rec.suggestedAction,
      focus,
    });
    forwardToAthena(text);
  }, [rec.title, rec.description, rec.suggestedAction, personaName, t, tx, forwardToAthena]);

  return (
    <div
      className={`animate-fade-slide-in rounded-modal border ${config.border} ${config.bg} overflow-hidden`}
    >
      <button
        onClick={() => setExpanded(!expanded)}
        className="w-full flex items-center gap-3 px-4 py-3 text-left hover:bg-primary/[0.04] transition-colors"
      >
        <div className={`w-8 h-8 rounded-card flex items-center justify-center flex-shrink-0 ${config.badge} border`}>
          <Icon className="w-4 h-4" />
        </div>
        <div className="flex-1 min-w-0">
          <div className="flex items-center gap-2">
            <span className="typo-heading text-foreground/90">
              {rec.title}
            </span>
            <span className={`typo-label px-1.5 py-0.5 rounded-input ${config.badge} border`}>
              {SEVERITY_LABEL[rec.severity] ?? rec.severity}
            </span>
          </div>
          <p className="typo-body text-foreground mt-0.5 truncate">
            {rec.description}
          </p>
        </div>
        <div className="flex-shrink-0 text-foreground">
          {expanded ? <ChevronUp className="w-4 h-4" /> : <ChevronDown className="w-4 h-4" />}
        </div>
      </button>

      {expanded && (
          <div
            className="animate-fade-slide-in overflow-hidden"
          >
            <div className="px-4 pb-3 pt-1 border-t border-primary/5 space-y-2.5">
              {/* Impact */}
              <div className="flex items-start gap-2">
                <span className="typo-label text-foreground mt-0.5 w-16 flex-shrink-0">
                  Impact
                </span>
                <span className="typo-body text-foreground">{rec.impact}</span>
              </div>

              {/* Action */}
              <div className="flex items-start gap-2">
                <span className="typo-label text-foreground mt-0.5 w-16 flex-shrink-0">
                  Action
                </span>
                <span className="typo-body text-foreground">{rec.suggestedAction}</span>
              </div>

              {/* Affected agents */}
              {rec.personaNames.length > 0 && (
                <div className="flex items-start gap-2">
                  <span className="typo-label text-foreground mt-0.5 w-16 flex-shrink-0">
                    Agent
                  </span>
                  <span className="typo-body text-foreground">
                    {rec.personaNames.join(', ')}
                  </span>
                </div>
              )}
            </div>
          </div>
        )}

      {/* Follow-up actions: tune the affected agent in its Lab, or hand the
          whole suggestion to Athena. Always visible (no expand needed). */}
      {showActions && (
        <div className="flex flex-wrap items-center gap-2 px-4 py-2.5 border-t border-primary/5">
          {personaId && (
            <Tooltip content={tx(t.overview.fleet_optimization.open_lab_hint, { persona: personaName ?? '' })}>
              <Button
                size="sm"
                variant="accent"
                accentColor="cyan"
                icon={<FlaskConical className="w-3.5 h-3.5" />}
                onClick={openLab}
              >
                {t.overview.fleet_optimization.open_lab}
              </Button>
            </Tooltip>
          )}
          <Tooltip content={t.overview.fleet_optimization.ask_athena_hint}>
            <Button
              size="sm"
              variant="accent"
              accentColor="violet"
              icon={<Sparkles className="w-3.5 h-3.5" />}
              onClick={askAthena}
            >
              {t.overview.fleet_optimization.ask_athena}
            </Button>
          </Tooltip>
        </div>
      )}
    </div>
  );
}

export default function FleetOptimizationCard() {
  const { t } = useTranslation();
  const { executionDashboard, healingIssues } = useOverviewStore(useShallow((s) => ({
    executionDashboard: s.executionDashboard,
    healingIssues: s.healingIssues,
  })));

  const recommendation = useMemo(
    () => generateFleetRecommendation(executionDashboard, healingIssues),
    [executionDashboard, healingIssues],
  );

  // Don't render anything if there's no recommendation or not enough data
  if (!recommendation) return null;

  // Don't show the "healthy fleet" card if there are very few executions
  if (recommendation.type === 'healthy_fleet' && (executionDashboard?.total_executions ?? 0) < 10) {
    return null;
  }

  return (
    <div className="space-y-1.5">
      <h3 className="typo-label text-foreground px-1 flex items-center gap-1.5">
        <Sparkles className="w-3 h-3" />
        {t.overview.fleet_optimization.title}
      </h3>
      <RecommendationContent rec={recommendation} />
    </div>
  );
}
